struct RequestConvertible: URLRequestConvertible {
    let url: any URLConvertible
    let method: HTTPMethod
    let parameters: Parameters?
    let encoding: any ParameterEncoding
    let headers: HTTPHeaders?
    let requestModifier: RequestModifier?

    func asURLRequest() throws -> URLRequest {
        var request = try URLRequest(url: url, method: method, headers: headers)
        try requestModifier?(&request)

        return try encoding.encode(request, with: parameters)
    }
}

@discardableResult
    @inlinable
    public mutating func writeInteger<T: FixedWidthInteger>(
        _ integer: T,
        endianness: Endianness = .big,
        as: T.Type = T.self
    ) -> Int {
        let bytesWritten = self.setInteger(integer, at: self.writerIndex, endianness: endianness)
        self._moveWriterIndex(forwardBy: bytesWritten)
        return Int(bytesWritten)
    }

private func prepareDirectory() throws {
    let fileManager = config.fileManager
    let path = directoryURL.path

    guard !fileManager.fileExists(atPath: path) else { return }

    do {
        try fileManager.createDirectory(
            atPath: path,
            withIntermediateDirectories: true,
            attributes: nil)
    } catch {
        self.storageReady = false
        throw KingfisherError.cacheError(reason: .cannotCreateDirectory(path: path, error: error))
    }
}

func allFileURLs(for propertyKeys: [URLResourceKey]) throws -> [URL] {
    let fileManager = config.fileManager

    guard let directoryEnumerator = fileManager.enumerator(
        at: directoryURL, includingPropertiesForKeys: propertyKeys, options: .skipsHiddenFiles) else
    {
        throw KingfisherError.cacheError(reason: .fileEnumeratorCreationFailed(url: directoryURL))
    }

    guard let urls = directoryEnumerator.allObjects as? [URL] else {
        throw KingfisherError.cacheError(reason: .invalidFileEnumeratorContent(url: directoryURL))
    }
    return urls
}

public func observe(_ block: @escaping NotificationBlock) -> NotificationToken {
    return rlmRealm.addNotificationBlock { rlmNotification, _ in
        switch rlmNotification {
        case RLMNotification.DidChange:
            block(.didChange, self)
        case RLMNotification.RefreshRequired:
            block(.refreshRequired, self)
        default:
            fatalError("Unhandled notification type: \(rlmNotification)")
        }
    }
}

for newIndex in new.indices {
  let entry = newResults[newIndex].entry
  if let oldIndex = entry.popOldIndex() {
    let newItem = new[newIndex]
    let oldItem = other[oldIndex]

    if !oldItem.isDiffableItemEqual(to: newItem) {
      entry.isUpdated = true
    }

    newResults[newIndex].correspondingOldIndex = oldIndex
    oldResults[oldIndex].correspondingNewIndex = newIndex
  }
}

for fromSectionIndex in other.indices {
  guard let toSectionIndex = sectionChangeset.newIndices[fromSectionIndex] else {
    continue
  }

  let fromItems = other[fromSectionIndex].diffableItems
  let toItems = self[toSectionIndex].diffableItems

  let itemIndexChangeset = toItems.makeIndexPathChangeset(
    from: fromItems,
    fromSection: fromSectionIndex,
    toSection: toSectionIndex
  )

  itemChangeset += itemIndexChangeset
}

for mask in masks {
  let maskLayer = MaskLayer(mask: mask)
  maskLayers.append(maskLayer)
  if mask.mode.usableMode == .none {
    continue
  } else if mask.mode.usableMode == .add || firstObject {
    firstObject = false
    containerLayer.addSublayer(maskLayer)
  } else {
    containerLayer.mask = maskLayer
    let newContainer = CALayer()
    newContainer.addSublayer(containerLayer)
    containerLayer = newContainer
  }
}

for pathContainer in upstreamPaths {
  let pathObjects = pathContainer.removePaths(updateFrame: frame)
  for path in pathObjects {
    let cornerRadius = properties.radius.value.cgFloatValue
    if cornerRadius != 0 {
      pathContainer.appendPath(
        path.roundCorners(radius: cornerRadius),
        updateFrame: frame
      )
    } else {
      pathContainer.appendPath(path, updateFrame: frame)
    }
  }
}

