}

switch result {
case let .fulfilled(webViewController):
    webViewController.dismissOverlayController(animated: true, completion: nil)
    if isComingFromAppIntent {
        webViewController.openPanel(url)
    } else {
        webViewController.open(inline: url, avoidUnnecessaryReload: avoidUnnecessaryReload)
    }
case .rejected:
    Current.Log.error("Failed to open WebViewController for server \(server.identifier)")
}

do {
    let existing = manager.providerConfiguration[PushProviderConfiguration.providerConfigurationKey] as? Data
    let new = try encoder.encode(configurations)

    if existing != new {
        isDirty = true
        manager.providerConfiguration = [
            PushProviderConfiguration.providerConfigurationKey: new,
        ]
    }
} catch {
    Current.Log.error("failed to create config for push: \(error)")
    manager.providerConfiguration = [:]
}

if isDirty {
    manager.saveToPreferences { [weak self] error in
        Current.Log.info("manager \(manager) saved, error: \(String(describing: error))")
        if let reason, let error {
            for server in servers {
                self?.logRetryDiagnostics(
                    reason: reason,
                    targetServer: server,
                    managers: [manager],
                    error: error
                )
            }
        }
    }
}

do {
    let credential = try ClientCertificateManager.shared.urlCredential(for: clientCertificate)
    Current.Log.info("Using client certificate: \(clientCertificate.displayName)")
    completionHandler(.useCredential, credential)
} catch {
    Current.Log.error("Failed to get credential for client certificate: \(error)")
    completionHandler(.cancelAuthenticationChallenge, nil)
}

if method == NSURLAuthenticationMethodClientCertificate {
    clientCertificateRequested = true
    completionHandler(.cancelAuthenticationChallenge, nil)
} else if method == NSURLAuthenticationMethodServerTrust {
    // Accept any server certificate for this test
    if let trust = challenge.protectionSpace.serverTrust {
        Current.Log.info("[mTLS] Accepting server trust")
        completionHandler(.useCredential, URLCredential(trust: trust))
    } else {
        completionHandler(.performDefaultHandling, nil)
    }
} else {
    completionHandler(.performDefaultHandling, nil)
}

if isSelected {
    if isMultipleSelection {
        // Checkmark for multiple selection
        Image(systemSymbol: .checkmark)
            .font(.caption.weight(.bold))
            .foregroundStyle(.haPrimary)
    } else {
        // Filled circle for single selection
        Circle()
            .fill(Color.haPrimary)
            .frame(width: 10, height: 10)
    }
}

if newValue.count == 1 {
    scheduleAutoConnect()
} else if newValue.count > 1 {
    cancelAutoConnect()
    // We display the loader a bit after instances are discovered
    // if there is just 1 server available we connect to it automatically
    // otherwise we display the list of servers
    scheduleCenterLoaderDimiss(
        amountOfTimeToWaitToDismissCenterLoader: Constants
            .minimumDelayUntilDismissCenterLoader
    )
}

if supportsMultipleScenes {
    activities.compactMap { activity in
        activity.userInfo?[Self.activityUserInfoKeyResolver] as? String
    }.compactMap { token in
        pendingResolvers[token]
    }.forEach { resolver in
        promise.done { resolver.resolve(with: $0) }
    }
} else {
    pendingResolvers
        .values
        .forEach { resolver in promise.done { resolver.resolve(with: $0) } }
}

if let backgroundTimestamp {
    let timeInterval = Current.date().timeIntervalSince(backgroundTimestamp)

    if timeInterval >= backgroundRefreshThreshold, Current.settingsStore.refreshWebViewAfterInactive {
        // Refresh WebViewController if it exists
        // Note: webViewControllerPromise is a Guarantee, which cannot fail in PromiseKit
        windowController?.webViewControllerPromise.done { webViewController in
            webViewController.refreshIfDisconnected()
        }
    }

    // Clear the timestamp
    self.backgroundTimestamp = nil
}

switch result {
case let .fulfilled(location):
    for api in Current.apis {
        api.SubmitLocation(updateType: .Launch, location: location, zone: nil).pipe { result in
            switch result {
            case .fulfilled:
                break // Submission succeeded, no action needed
            case let .rejected(error):
                Current.Log.error("Failed to submit location: \(error)")
            }
        }
    }
case let .rejected(error):
    Current.Log.error("Failed to get location on sceneDidBecomeActive: \(error)")
}

if let account = account, let credentials = try? account.retrieveCredentials(type: .basic) {
	usernameTextField.stringValue = credentials.username
	actionButton.title = NSLocalizedString("Update", comment: "Update")
	signInTextField.stringValue = NSLocalizedString("Update your Feedbin account credentials.", comment: "SignIn")
	noAccountTextField.isHidden = true
	createNewAccountButton.isHidden = true
} else {
	actionButton.title = NSLocalizedString("Create", comment: "Create")
	signInTextField.stringValue = NSLocalizedString("Sign in to your Feedbin account.", comment: "SignIn")
}

if let containerList = container as? [Any] {
    for nthObject in containerList {
        self.delete(specifier: specifier, from: nthObject)
    }
} else if let container = container as? ScriptingObjectContainer {
    if let resolvedObjects = specifier.objectsByEvaluating(withContainers: container) {
        self.delete(objectToDelete: resolvedObjects, from: container)
    }
}

switch result {
case .success(let feed):
	NotificationCenter.default.post(name: .UserDidAddFeed, object: self, userInfo: [UserInfoKey.feed: feed])
	let scriptableFeed = self.scriptableFeed(feed, account: account, folder: folder)
	command.resumeExecution(withResult: scriptableFeed.objectSpecifier)
case .failure:
	command.resumeExecution(withResult: nil)
}

do {
	try await account.logActivity(kind: .moveFeed, detail: feed.url) {
		try await accountZone.moveFeed(feed, from: sourceContainer, to: destinationContainer)
		sourceContainer.removeFeedFromTreeAtTopLevel(feed)
		destinationContainer.addFeedToTreeAtTopLevel(feed)
	}
} catch {
	postSyncError(error, account: account, operation: "Moving feed")
	throw error
}

do {
	try await account.logActivity(kind: .restoreFeed, detail: feed.url) {
		let externalID = try await accountZone.createFeed(url: feed.url,
														  name: feed.name,
														  editedName: feed.editedName,
														  homePageURL: feed.homePageURL,
														  container: container)
		feed.externalID = externalID
	}
	syncProgress.completeTask()
} catch {
	syncProgress.completeTask()
	container.removeFeedFromTreeAtTopLevel(feed)
	postSyncError(error, account: account, operation: "Restoring feed")
	throw error
}

do {
	return try await account.logActivity(kind: .createFolder, detail: name) {
		let externalID = try await accountZone.createFolder(name: name)
		guard let folder = account.ensureFolder(with: name) else {
			throw AccountError.invalidParameter
		}
		folder.externalID = externalID
		return folder
	}
} catch {
	postSyncError(error, account: account, operation: "Creating folder")
	throw error
}

for feed in feeds {
	group.addTask {
		do {
			try await account.logActivity(kind: .removeFeed, detail: feed.url) {
				try await self.removeFeedFromCloud(for: account, with: feed, from: folder)
			}
			return (feed, nil)
		} catch {
			Self.logger.error("CloudKit: Remove folder, remove feed error: \(error.localizedDescription)")
			return (feed, error)
		}
	}
}

guard failedFeeds.isEmpty else {
	// Best-effort restore: bring the folder back with only the feeds that failed to delete
	// from CloudKit. Successfully-removed feeds stay gone locally to match cloud state.
	syncProgress.completeTask()
	folder.replaceTopLevelFeeds(failedFeeds)
	account.addFolderToTree(folder)
	throw CloudKitAccountDelegateError.unknown
}

do {
	try await accountZone.removeFolder(folder)
	syncProgress.completeTask()
} catch {
	syncProgress.completeTask()
	// All feeds were removed from CloudKit but the folder record removal failed.
	// Restore an empty folder locally so it matches the cloud and the user can retry.
	folder.replaceTopLevelFeeds([])
	account.addFolderToTree(folder)
	throw error
}

public final class ConstraintItem {

    internal weak var target: AnyObject?
    internal let attributes: ConstraintAttributes

    internal init(target: AnyObject?, attributes: ConstraintAttributes) {
        self.target = target
        self.attributes = attributes
    }

    internal var layoutConstraintItem: LayoutConstraintItem? {
        return self.target as? LayoutConstraintItem
    }

}

public func update(offset: ConstraintOffsetTarget) -> Constraint {
        self.constant = offset.constraintOffsetTargetValue
        return self
    }

    @discardableResult
    public func update(inset: ConstraintInsetTarget) -> Constraint {
        self.constant = inset.constraintInsetTargetValue
        return self
    }

    #if canImport(UIKit)

internal func deactivateIfNeeded() {
    guard let item = self.from.layoutConstraintItem else {
        print("WARNING: SnapKit failed to get from item from constraint. Deactivate will be a no-op.")
        return
    }
    let layoutConstraints = self.layoutConstraints
    NSLayoutConstraint.deactivate(layoutConstraints)
    item.remove(constraints: [self])
}

public func collect(max: Int? = 1 << 14) -> EventLoopFuture<ByteBuffer?> {
    switch self.request.bodyStorage.withLockedValue({ $0 }) {
    case .stream(let stream):
        return stream.consume(max: max, on: self.request.eventLoop).map { buffer in
            self.request.bodyStorage.withLockedValue({ $0 = .collected(buffer) })
            return buffer
        }
    case .collected(let buffer):
        return self.request.eventLoop.makeSucceededFuture(buffer)
    case .none:
        return self.request.eventLoop.makeSucceededFuture(nil)
    }
}

